def rob(self, nums: list[int]) -> int:
    a = b = 0
    for x in nums:
        a, b = b, max(b, a + x)
    return b

def rob_dp(self, nums: list[int]) -> int:
    if not nums:
        return 0
    n = len(nums)
    f = [0] * (n + 1)
    f[1] = nums[0]
    for i in range(2, n + 1):
        f[i] = max(f[i - 1], f[i - 2] + nums[i - 1])
    return f[n]
